from flask import Flask, request, redirect, url_for
from oauthlib.oauth2 import WebApplicationClient
import requests

app = Flask(__name__)

# Load the client configuration from a file or database
client_config = {
    "client_id": "your-client-id",
    "client_secret": "your-client-secret",
    "redirect_uri": "https://example.com/oauth2/callback"
}

# Create an OAuth 2.0 client instance
client = WebApplicationClient(client_config["client_id"],
                              client_config["client_secret"])

@app.route("/")
def index():
    # Initiate the authorization flow by redirecting the user to the authorization URL
    authorization_url, state = client.authorization_url(
        "https://example.com/oauth2/authorize",
        redirect_uri=client_config["redirect_uri"]
    )
    return redirect(authorization_url)

@app.route("/oauth2/callback")
def callback():
    # Exchange the authorization code for an access token
    try:
        token = client.fetch_token(
            "https://example.com/oauth2/token",
            authorization_response=request.url,
            redirect_uri=client_config["redirect_uri"]
        )
        # Use the access token to make an API request
        response = requests.get("https://example.com/api/resource",
                                headers={"Authorization": f"Bearer {token}"})
        return "Resource: {}".format(response.json())
    except Exception as e:
        return str(e)